<?php
 namespace League\CommonMark\Block\Element; use League\CommonMark\ContextInterface; use League\CommonMark\Cursor; class Paragraph extends AbstractStringContainerBlock implements InlineContainerInterface { public function canContain(AbstractBlock $block): bool { return false; } public function isCode(): bool { return false; } public function matchesNextLine(Cursor $cursor): bool { if ($cursor->isBlank()) { $this->lastLineBlank = true; return false; } return true; } public function finalize(ContextInterface $context, int $endLineNumber) { parent::finalize($context, $endLineNumber); $this->finalStringContents = \preg_replace('/^  */m', '', \implode("\n", $this->getStrings())); if ($this->finalStringContents === '' || $this->finalStringContents[0] !== '[') { return; } $cursor = new Cursor($this->finalStringContents); $referenceFound = $this->parseReferences($context, $cursor); $this->finalStringContents = $cursor->getRemainder(); if ($referenceFound && $cursor->isAtEnd()) { $this->detach(); } } protected function parseReferences(ContextInterface $context, Cursor $cursor) { $referenceFound = false; while ($cursor->getCharacter() === '[' && $context->getReferenceParser()->parse($cursor)) { $this->finalStringContents = $cursor->getRemainder(); $referenceFound = true; } return $referenceFound; } public function handleRemainingContents(ContextInterface $context, Cursor $cursor) { $cursor->advanceToNextNonSpaceOrTab(); $tip = $context->getTip(); $tip->addLine($cursor->getRemainder()); } public function getStrings(): array { return $this->strings->toArray(); } } 